/*
    CLEAN BATCH VERSION
    1. Works with Selection.
    2. Silently fixes errors.
    3. Smart pre-flight (Actual PPI + CMYK/Default Profile).
    4. Final report only.
*/

#target indesign

function main() {
    // --- SETTINGS ---
    var actionName = "Prepare_catalog"; 
    var actionSet = "Print_prepare";    
    var minPPI = 295; 
    // -----------------

    if (app.selection.length == 0) {
        alert("Nothing selected! Select images.");
        return;
    }

    var sel = app.selection;
    var counter = 0;
    var scanned = 0;

    // Progress window
    var win = new Window("palette", "Processing...", undefined);
    var statusText = win.add("statictext", [0, 0, 400, 20], "Initializing...");
    win.show();

    for (var i = 0; i < sel.length; i++) {
        var item = sel[i];
        var img = null;

        // Find graphics
        if (item.hasOwnProperty("allGraphics") && item.allGraphics.length > 0) {
            img = item.allGraphics[0];
        } else if (item instanceof Image || item instanceof EPS || item instanceof PDF) {
            img = item;
        }

        if (img == null) continue;

        var link = img.itemLink;
        if (!link || link.status == LinkStatus.LINK_MISSING) continue;

        scanned++;

        // --- 1. CHECK PPI ---
        var currentPPI = 0;
        try {
            currentPPI = Math.round(img.actualPpi[0]);
        } catch(e) { currentPPI = 300; } // Treat vectors as OK

        // --- 2. CHECK COLOR SPACE ---
        var spaceRaw = img.space;
        var profileName = "";
        try {
            profileName = img.profile;
        } catch(e) {}

        var isCMYK = false;

        // If CMYK
        if (spaceRaw == ColorSpace.CMYK) {
            isCMYK = true;
        }
        // If profile name contains specific keywords
        else if (profileName && profileName.match(/cmyk|coated|fogra|iso|euroscale|default|document/i)) {
            isCMYK = true;
        }

        // --- DECISION ---
        if (!isCMYK || currentPPI < minPPI) {

            statusText.text = "Fixing: " + link.name;
            win.update();

            var filePath = link.filePath;

            // Treat
            var success = processInPhotoshop(filePath, actionName, actionSet);

            if (success) {
                link.update();
                counter++;
            }
        } else {
            // Skip (OK)
            statusText.text = "Skip (OK): " + link.name;
            win.update();
        }
    }

    win.close();

    // --- FINAL REPORT ---
    if (counter > 0) {
        alert("Done!\nChecked files: " + scanned + "\nErrors fixed: " + counter);
    } else {
        alert("Great job!\nChecked files: " + scanned + "\nAll files are fine (no processing needed).");
    }
}

function processInPhotoshop(path, actName, actSet) {
    var bt = new BridgeTalk();
    bt.target = "photoshop";
    // try-catch inside PS
    var scriptCode = 'try {' +
        'var doc = app.open(new File("' + path.replace(/\\/g, "\\\\") + '"));' + 
        'app.doAction("' + actName + '", "' + actSet + '");' + 
        'doc.close(SaveOptions.SAVECHANGES);' + 
        '} catch(e) { alert("PS Error: " + e); }';
    bt.body = scriptCode;
    bt.send(90); 
    return true;
}

main();
